/******/ (() => { // webpackBootstrap
/*!********************************************!*\
  !*** ./src/scripts/sections/contact-us.js ***!
  \********************************************/
document.addEventListener("DOMContentLoaded", () => {
  const form = document.getElementById("contact-form");
  if (!form) return;

  const submitButton = form.querySelector(".contact-us__submit");
  const formMessage = document.getElementById("form-message");

  // Get translations (with fallbacks)
  const t = window.contactUsTranslations || {
    errors: {},
    success: "Thank you! We'll get back to you soon.",
    error_sending: "There was an error sending your message. Please try again.",
    sending: "Sending...",
    button_text: "Send Message",
  };

  // Validation functions
  const validators = {
    first_name: (value) => {
      if (!value.trim()) return t.errors.first_name_required;
      if (value.trim().length < 2) return t.errors.first_name_min;
      return "";
    },
    last_name: (value) => {
      if (!value.trim()) return t.errors.last_name_required;
      if (value.trim().length < 2) return t.errors.last_name_min;
      return "";
    },
    phone: (value) => {
      const phoneRegex = /^[\d\s\-\+\(\)]+$/;
      if (!value.trim()) return t.errors.phone_required;
      if (value.trim().length < 7) return t.errors.phone_invalid;
      if (!phoneRegex.test(value)) return t.errors.phone_format;
      return "";
    },
  };

  // Map input name -> error element id (underscores to hyphens)
  const getErrorId = (name) => `${name.replace(/_/g, "-")}-error`;

  function decodeHTMLEntities(text) {
    const textarea = document.createElement("textarea");
    textarea.innerHTML = text;
    return textarea.value;
  }

  const validateField = (fieldName, value) => {
    const validator = validators[fieldName];
    const errorElement = document.getElementById(getErrorId(fieldName));
    if (!validator || !errorElement) return true;

    const error = validator(value);
    errorElement.textContent = decodeHTMLEntities(error);
    return !error;
  };

  // Clear/validate error on field change
  form.querySelectorAll(".contact-us__input").forEach((input) => {
    input.addEventListener("input", () =>
      validateField(input.name, input.value),
    );
    input.addEventListener("blur", () =>
      validateField(input.name, input.value),
    );
  });

  // Button click handler
  submitButton.addEventListener("click", async () => {
    let isValid = true;
    form.querySelectorAll(".contact-us__input").forEach((input) => {
      if (!validateField(input.name, input.value)) {
        isValid = false;
      }
    });

    if (!isValid) {
      showMessage(t.errors.fix_errors, "error");
      return;
    }

    const getValue = (name) =>
      form.querySelector(`[name="${name}"]`)?.value || "";

    const data = {
      name: getValue("first_name"),
      surname: getValue("last_name"),
      phone: getValue("phone").replace(/\D/g, ""),
    };

    // Loading state
    submitButton.disabled = true;
    submitButton.textContent = t.sending;

    try {
      const apiEndpoint =
        "https://form-production-51a4.up.railway.app/api/save-customer-data";
      const response = await fetch(apiEndpoint, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      });

      if (response.ok) {
        showMessage(t.success, "success");

        form.querySelectorAll(".contact-us__input").forEach((input) => {
          input.value = "";
        });
        form.querySelectorAll(".contact-us__error").forEach((el) => {
          el.textContent = "";
        });

        setTimeout(() => {
          submitButton.disabled = false;
          submitButton.textContent = t.button_text;
        }, 5000);
      } else {
        showMessage(t.error_sending, "error");
        submitButton.disabled = false;
        submitButton.textContent = t.button_text;
      }
    } catch (error) {
      console.error("Form submission error:", error);
      showMessage(t.error_sending, "error");
      submitButton.disabled = false;
      submitButton.textContent = t.button_text;
    }
  });

  function showMessage(message, type) {
    formMessage.textContent = decodeHTMLEntities(message);
    formMessage.className = `contact-us__message ${type}`;

    if (type === "success") {
      setTimeout(() => {
        formMessage.className = "contact-us__message";
        formMessage.textContent = "";
      }, 5000);
    }
  }
});

/******/ })()
;